import java.util.*;
import java.util.stream.Collectors;

// ── Domain Events ────────────────────────────────────────────
sealed interface AccountEvent permits Deposited, Withdrawn, Opened {}
record Opened(String accountId, String owner) implements AccountEvent {}
record Deposited(String accountId, double amount) implements AccountEvent {}
record Withdrawn(String accountId, double amount) implements AccountEvent {}

// ── EventStore (in-memory for demo) ─────────────────────────
class EventStore {
    private final List<AccountEvent> events = new ArrayList<>();

    void append(AccountEvent event) { events.add(event); }

    List<AccountEvent> getEvents(String accountId) {
        return events.stream()
            .filter(e -> getAccountId(e).equals(accountId))
            .collect(Collectors.toList());
    }

    private String getAccountId(AccountEvent e) {
        return switch (e) {
            case Opened    o -> o.accountId();
            case Deposited d -> d.accountId();
            case Withdrawn w -> w.accountId();
        };
    }
}

// ── Aggregate: replays events to compute current state ───────
class Account {
    String id;
    String owner;
    double balance;

    // Reconstruct from event history
    static Account fromEvents(List<AccountEvent> events) {
        Account acc = new Account();
        for (AccountEvent e : events) acc.apply(e);
        return acc;
    }

    void apply(AccountEvent e) {
        switch (e) {
            case Opened    o -> { id = o.accountId(); owner = o.owner(); balance = 0; }
            case Deposited d -> balance += d.amount();
            case Withdrawn w -> balance -= w.amount();
        }
    }
}

// ── Outbox Pattern ───────────────────────────────────────────
record OutboxEntry(String eventType, String payload, boolean published) {}

class OutboxService {
    // In real code: outbox writes are in the SAME @Transactional as domain writes
    private final List<OutboxEntry> outbox = new ArrayList<>();

    void writeToOutbox(String eventType, String payload) {
        outbox.add(new OutboxEntry(eventType, payload, false));
    }

    // Poller (scheduled every second): reads unpublished, sends to Kafka
    List<OutboxEntry> getUnpublished() {
        return outbox.stream().filter(e -> !e.published()).collect(Collectors.toList());
    }
}

public class EventSourcingDemo {
    public static void main(String[] args) {
        EventStore store = new EventStore();
        OutboxService outbox = new OutboxService();

        // === Commands (write side) ===
        String accId = "acc-001";

        // 1. Open account
        store.append(new Opened(accId, "Alice"));
        outbox.writeToOutbox("ACCOUNT_OPENED", "{\"accountId\":\"acc-001\"}");

        // 2. Deposit
        store.append(new Deposited(accId, 500.0));
        outbox.writeToOutbox("MONEY_DEPOSITED", "{\"amount\":500}");

        // 3. Withdraw
        store.append(new Withdrawn(accId, 150.0));
        outbox.writeToOutbox("MONEY_WITHDRAWN", "{\"amount\":150}");

        // === Queries (read side) ===
        List<AccountEvent> history = store.getEvents(accId);
        Account current = Account.fromEvents(history);

        System.out.println("Account: " + current.id);
        System.out.println("Owner:   " + current.owner);
        System.out.printf("Balance: %.1f%n", current.balance); // 350.0

        // Time travel: what was the balance after the deposit?
        Account afterDeposit = Account.fromEvents(history.subList(0, 2));
        System.out.printf("After deposit: %.1f%n", afterDeposit.balance); // 500.0

        // Outbox entries waiting to be published
        System.out.println("Outbox pending: " + outbox.getUnpublished().size()); // 3
        outbox.getUnpublished().forEach(e -> System.out.println("  → " + e.eventType()));
    }
}

