import java.util.*;

public class Q2 {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        Map<String, int[]> readModel = new TreeMap<>();
        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) continue;
            String[] p = line.split(" ");
            String event = p[0], cid = p[1];
            int amount = Integer.parseInt(p[2]);
            readModel.putIfAbsent(cid, new int[]{0, 0});
            int[] v = readModel.get(cid);
            if (event.equals("ORDER_PLACED"))    { v[0]++; v[1] += amount; }
            else if (event.equals("ORDER_CANCELLED")) { v[1] -= amount; }
        }
        readModel.forEach((k, v) -> System.out.println(k + " " + v[0] + " " + v[1]));
    }
}

